from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

# Replace with your Ethereum node URL
WEB3_NODE_URL = 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'
web3 = Web3(Web3.HTTPProvider(WEB3_NODE_URL))

def verify_signature(message, signature, address):
    message_hash = web3.solidityKeccak(['string'], [message])
    recovered_address = web3.eth.account.recover(message_hash, signature=signature)
    return recovered_address.lower() == address.lower()

@app.route('/verify', methods=['POST'])
def verify():
    data = request.get_json()
    if 'message' not in data or 'signature' not in data or 'address' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    message = data['message']
    signature = data['signature']
    address = data['address']

    if verify_signature(message, signature, address):
        return jsonify({'authenticated': True}), 200
    else:
        return jsonify({'authenticated': False}), 401

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)